// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 {
    function transferFrom(address sender, address recipient, uint256 amount) external returns (bool);
    function transfer(address recipient, uint256 amount) external returns (bool);
}

contract ArcenticSwapPools_V2 {
    address public tokenA;
    address public tokenB;
    uint256 public reserveA;
    uint256 public reserveB;

    constructor(address _tokenA, address _tokenB) {
        tokenA = _tokenA;
        tokenB = _tokenB;
    }

    // Fungsi untuk menambah likuiditas (set harga)
    function addLiquidity(uint256 amountA, uint256 amountB) external {
        IERC20(tokenA).transferFrom(msg.sender, address(this), amountA);
        IERC20(tokenB).transferFrom(msg.sender, address(this), amountB);
        reserveA += amountA;
        reserveB += amountB;
    }

    // Fungsi untuk swap (CENTIC ke USDC atau sebaliknya)
    function swap(address _tokenIn, uint256 _amountIn) external returns (uint256 amountOut) {
        require(_tokenIn == tokenA || _tokenIn == tokenB, "Invalid token");
        
        bool isTokenA = (_tokenIn == tokenA);
        IERC20(_tokenIn).transferFrom(msg.sender, address(this), _amountIn);

        if (isTokenA) {
            amountOut = (_amountIn * reserveB) / (reserveA + _amountIn);
            reserveA += _amountIn;
            reserveB -= amountOut;
            IERC20(tokenB).transfer(msg.sender, amountOut);
        } else {
            amountOut = (_amountIn * reserveA) / (reserveB + _amountIn);
            reserveB += _amountIn;
            reserveA -= amountOut;
            IERC20(tokenA).transfer(msg.sender, amountOut);
        }
    }
}

